1	// claim-office.ts
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: string; items: unknown[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	export const processScenario = (scenario: Scenario): ScenarioResult => {
15	  const premium =
16	    scenario.steps[0].items.length === 0 ? PROCESSING_FEE : 115;
17	  return { results: [{ premium }] };
18	};
